#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        min1 = 10**18
        min2 = 10**18
        for _ in range(N):
            x = int(next(it))
            if x < min1:
                min2 = min1
                min1 = x
            elif x < min2:
                min2 = x
        total = min1 + min2
        out_lines.append('CHEF' if total & 1 else 'CHEFINA')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

